settings.custom_liquid:
{% assign tags_string = product.tags | join: '|' | downcase %}

<style>
/* BUTTON */
.size-chart-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: none;
  border: none;
  cursor: pointer;
  font-size: 14px;
  padding: 0;
}

.size-chart-btn span {
  color: #e00000;
  font-weight: 500;
}
.size-chart-btn span {
  color: black;
  text-decoration: none;
}
.size-chart-btn{
text-decoration: none;
}

/* MODAL OVERLAY */
.size-chart-modal {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.45);
  display: none;
  z-index: 9999;
}

.size-chart-modal.active {
  display: flex;
  align-items: center;
  justify-content: center;
}

/* MODAL CONTENT */
.size-chart-modal-content {
  background: #fff;
  width: 92%;
  max-width: 520px;
  max-height: 85vh;        /* 👈 critical */
  border-radius: 8px;
  position: relative;
  overflow-y: auto;        /* 👈 critical */
  padding: 20px 16px 24px;
  box-sizing: border-box;
}

.size-chart-close {
  position: sticky;
  top: 0;
  margin-left: auto;
  display: block;
  font-size: 24px;
  background: none;
  border: none;
  cursor: pointer;
  line-height: 1;
}

/* TABLE */
.size-chart-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 12px;
  font-size: 14px;
}

.size-chart-table th,
.size-chart-table td {
  padding: 8px;
  border-bottom: 1px solid #eee;
  text-align: center;
}

.size-chart-table th {
  font-weight: 600;
  background: #fafafa;
}
</style>

<!-- BUTTON -->
<button class="size-chart-btn" type="button" onclick="openSizeChart()">
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="5" height="5">
    <path d="M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10 10-4.5 10-10S17.5 2 12 2z"/>
  </svg>
  <span>Size Chart</span>
</button>

<!-- MODAL -->
<div id="sizeChartModal" class="size-chart-modal" onclick="overlayClose(event)">
  <div class="size-chart-modal-content">
    <button class="size-chart-close" type="button" onclick="closeSizeChart()">&times;</button>

    <h2 style="margin: 0 0 8px;">Size Chart</h2>

    <table class="size-chart-table">
      <thead>
        <tr>
          <th>Size</th>
          <th>Chest (in)</th>
          <th>Waist (in)</th>
          <th>Length (in)</th>
        </tr>
      </thead>

      <tbody>
        {% if tags_string contains 'footwear' and tags_string contains 'female' %}
          <tr><td colspan="4"><strong>Girls Footwear</strong></td></tr>
          {% for size in (5..11) %}
            <tr>
              <td>{{ size }}</td>
              <td colspan="3">Standard Fit</td>
            </tr>
          {% endfor %}

        {% elsif tags_string contains 'footwear' and tags_string contains 'male' %}
          <tr><td colspan="4"><strong>Boys Footwear</strong></td></tr>
          {% for size in (6..12) %}
            <tr>
              <td>{{ size }}</td>
              <td colspan="3">Standard Fit</td>
            </tr>
          {% endfor %}

        {% elsif tags_string contains 'female' %}
          <tr><td>XS</td><td>32–33</td><td>24–25</td><td>26</td></tr>
          <tr><td>S</td><td>34–35</td><td>26–27</td><td>26.5</td></tr>
          <tr><td>M</td><td>36–37</td><td>28–29</td><td>27</td></tr>
          <tr><td>L</td><td>38–39</td><td>30–31</td><td>27.5</td></tr>
          <tr><td>XL</td><td>40–41</td><td>32–33</td><td>28</td></tr>

        {% else %}
          <tr><td>S</td><td>36–38</td><td>28–30</td><td>27</td></tr>
          <tr><td>M</td><td>39–40</td><td>31–32</td><td>28</td></tr>
          <tr><td>L</td><td>41–42</td><td>33–34</td><td>29</td></tr>
          <tr><td>XL</td><td>43–44</td><td>35–36</td><td>30</td></tr>
          <tr><td>XXL</td><td>45–46</td><td>37–38</td><td>31</td></tr>
        {% endif %}
      </tbody>
    </table>
  </div>
</div>

<script>
function openSizeChart() {
  document.getElementById('sizeChartModal').classList.add('active');
}

function closeSizeChart() {
  document.getElementById('sizeChartModal').classList.remove('active');
}

function overlayClose(e) {
  if (e.target.id === 'sizeChartModal') {
    closeSizeChart();
  }
}
</script>
